@app.get("/annotators/{annotator_id}/stats")
def get_annotator_stats(annotator_id: str):
    """Get statistics for a specific annotator."""
    if annotator_id not in annotator_registry:
        raise HTTPException(status_code=404, detail="Annotator not found")

    # Calculate annotator-specific stats
    annotator_annotations = []
    agreements = []

    for image_id, annotations in annotation_store.items():
        for ann in annotations:
            if ann["annotator_id"] == annotator_id:
                annotator_annotations.append({
                    "image_id": image_id,
                    "label": ann["label"],
                    "confidence": ann["confidence"],
                })
                # Check if annotator agreed with majority
                if image_id in aggregated_labels:
                    majority_label = aggregated_labels[image_id]["label"]
                    agreements.append(1 if ann["label"] == majority_label else 0)

    agreement_rate = sum(agreements) / len(agreements) if agreements else None

    return {
        "annotator_id": annotator_id,
        "info": annotator_registry[annotator_id],
        "total_annotations": len(annotator_annotations),
        "agreement_with_majority": round(agreement_rate, 4) if agreement_rate is not None else None,
        "annotations": annotator_annotations,
    }


