@app.post("/images/upload")
async def upload_image(file: UploadFile = File(...), image_id: Optional[str] = Form(default=None)):
    """Upload an image for labeling."""
    if image_id is None:
        image_id = str(uuid.uuid4())

    if image_id in image_store:
        raise HTTPException(status_code=400, detail="Image ID already exists")

    data = await file.read()

    # Validate it's a valid image if PIL is available
    if TORCH_AVAILABLE:
        try:
            img = Image.open(BytesIO(data))
            img.verify()
        except Exception:
            raise HTTPException(status_code=400, detail="Invalid image file")

    image_store[image_id] = {
        "filename": file.filename,
        "data": data,
        "size_bytes": len(data),
    }
    annotation_store[image_id] = []

    return {"message": "Image uploaded successfully", "image_id": image_id}


