# --- Annotation Management ---

@app.post("/annotations")
def submit_annotation(annotation: AnnotationSubmission):
    """Submit a label annotation for an image."""
    if annotation.image_id not in image_store:
        raise HTTPException(status_code=404, detail="Image not found")

    if annotation.annotator_id not in annotator_registry:
        raise HTTPException(status_code=404, detail="Annotator not registered. Please register first.")

    # Check for duplicate annotation
    existing = annotation_store.get(annotation.image_id, [])
    for ann in existing:
        if ann["annotator_id"] == annotation.annotator_id:
            raise HTTPException(
                status_code=400,
                detail="This annotator has already labeled this image. Use PUT to update."
            )

    annotation_data = {
        "annotator_id": annotation.annotator_id,
        "label": annotation.label,
        "confidence": annotation.confidence,
    }

    annotation_store[annotation.image_id].append(annotation_data)
    label_registry.add(annotation.label)
    annotator_registry[annotation.annotator_id]["annotations_count"] += 1

    # Re-aggregate labels for this image
    agg = aggregate_labels_for_image(annotation.image_id)

    return {
        "message": "Annotation submitted successfully",
        "image_id": annotation.image_id,
        "current_aggregation": agg,
    }


@app.post("/annotations/batch")
def submit_batch_annotations(batch: BatchAnnotationSubmission):
    """Submit multiple annotations at once."""
    results = []
    for annotation in batch.annotations:
        try:
            if annotation.image_id not in image_store:
                results.append({"image_id": annotation.image_id, "status": "error", "detail": "Image not found"})
                continue

            if annotation.annotator_id not in annotator_registry:
                results.append({"image_id": annotation.image_id, "status": "error", "detail": "Annotator not registered"})
                continue

            existing = annotation_store.get(annotation.image_id, [])
            duplicate = any(a["annotator_id"] == annotation.annotator_id for a in existing)
            if duplicate:
                results.append({"image_id": annotation.image_id, "status": "error", "detail": "Duplicate annotation"})
                continue

            annotation_data = {
                "annotator_id": annotation.annotator_id,
                "label": annotation.label,
                "confidence": annotation.confidence,
            }
            annotation_store[annotation.image_id].append(annotation_data)
            label_registry.add(annotation.label)
            annotator_registry[annotation.annotator_id]["annotations_count"] += 1

            aggregate_labels_for_image(annotation.image_id)
            results.append({"image_id": annotation.image_id, "status": "success"})

        except Exception as e:
            results.append({"image_id": annotation.image_id, "status": "error", "detail": str(e)})

    return {
        "results": results,
        "total_success": sum(1 for r in results if r["status"] == "success"),
        "total_errors": sum(1 for r in results if r["status"] == "error"),
    }


@app.put("/annotations/{image_id}/{annotator_id}")
def update_annotation(image_id: str, annotator_id: str, label: str, confidence: float = 1.0):
    """Update an existing annotation."""
    if image_id not in annotation_store:
        raise HTTPException(status_code=404, detail="Image not found")

    for ann in annotation_store[image_id]:
        if ann["annotator_id"] == annotator_id:
            ann["label"] = label
            ann["confidence"] = confidence
            label_registry.add(label)
            aggregate_labels_for_image(image_id)
            return {"message": "Annotation updated successfully"}

    raise HTTPException(status_code=404, detail="Annotation not found for this annotator and image")


@app.delete("/annotations/{image_id}/{annotator_id}")
def delete_annotation(image_id: str, annotator_id: str):
    """Delete an annotation."""
    if image_id not in annotation_store:
        raise HTTPException(status_code=404, detail="Image not found")

    original_len = len(annotation_store[image_id])
    annotation_store[image_id] = [
        a for a in annotation_store[image_id] if a["annotator_id"] != annotator_id
    ]

    if len(annotation_store[image_id]) == original_len:
        raise HTTPException(status_code=404, detail="Annotation not found")

    if annotator_id in annotator_registry:
        annotator_registry[annotator_id]["annotations_count"] -= 1

    aggregate_labels_for_image(image_id)
    return {"message": "Annotation deleted successfully"}


