@app.get("/stats/inter_annotator_agreement")
def get_inter_annotator_agreement():
    """Calculate inter-annotator agreement metrics."""
    # Calculate pairwise agreement between annotators
    annotator_pairs = {}
    annotator_ids = list(annotator_registry.keys())

    for i, a1 in enumerate(annotator_ids):
        for a2 in annotator_ids[i + 1:]:
            pair_key = f"{a1}_vs_{a2}"
            agreements = 0
            total = 0

            for image_id, annotations in annotation_store.items():
                labels_by_annotator = {a["annotator_id"]: a["label"] for a in annotations}
                if a1 in labels_by_annotator and a2 in labels_by_annotator:
                    total += 1
                    if labels_by_annotator[a1] == labels_by_annotator[a2]:
                        agreements += 1

            if total > 0:
                annotator_pairs[pair_key] = {
                    "agreement_rate": round(agreements / total, 4),
                    "shared_images": total,
                    "agreements": agreements,
                }

    overall_agreements = [p["agreement_rate"] for p in annotator_pairs.values()]
    overall_avg = sum(overall_agreements) / len(overall_agreements) if overall_agreements else None

    return {
        "pairwise_agreements": annotator_pairs,
        "overall_average_agreement": round(overall_avg, 4) if overall_avg is not None else None,
    }


# --- Model Training & Prediction ---

@app.post("/model/train")
def train_model(config: TrainingConfig):
    """Train a classification model on the aggregated labeled data."""
    global trained_model_weights, model_state

    if not TORCH_AVAILABLE:
        raise HTTPException(status_code=500, detail="PyTorch is not installed. Cannot train model.")

    # Ensure labels are aggregated
    aggregate_all_labels()

    # Filter samples based on agreement threshold
    training_image_ids = []
    training_labels = []

    for image_id, agg in aggregated_labels.items():
        if agg["agreement"] >= config.min_agreement and image_id in image_store:
            training_image_ids.append(image_id)
            training_labels.append(agg["label"])

    if len(training_image_ids) == 0:
        raise HTTPException(
            status_code=400,
            detail="No training samples available. Upload images and submit annotations first."
        )

    unique_labels = sorted(set(training_labels))
    num_classes = len(unique_labels)

    if num_classes < 2:
        raise HTTPException(status_code=400, detail="Need at least 2 different labels to train a classifier.")

    label_to_idx = {label: idx for idx, label in enumerate(unique_labels)}
    idx_to_label = {idx: label for label, idx in label_to_idx.items()}

    # Create dataset and dataloader - NO validation split
    dataset = LabeledImageDataset(
        training_image_ids, training_labels, label_to_idx, image_size=config.image_size
    )
    dataloader = DataLoader(dataset, batch_size=config.batch_size, shuffle=True)

    # Create model
    device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
    model = create_model(num_classes, freeze_backbone=config.freeze_backbone)
    model = model.to(device)

    criterion = nn.CrossEntropyLoss()
    optimizer = optim.Adam(filter(lambda p: p.requires_grad, model.parameters()), lr=config.learning_rate)

    # Training loop - NO validation
    training_history = []
    model.train()

    for epoch in range(config.epochs):
        running_loss = 0.0
        correct = 0
        total = 0

        for batch_images, batch_labels in dataloader:
            batch_images = batch_images.to(device)
            batch_labels = batch_labels.to(device)

            optimizer.zero_grad()
            outputs = model(batch_images)
            loss = criterion(outputs, batch_labels)
            loss.backward()
            optimizer.step()

            running_loss += loss.item() * batch_images.size(0)
            _, predicted = torch.max(outputs.data, 1)
            total += batch_labels.size(0)
            correct += (predicted == batch_labels).sum().item()

        epoch_loss = running_loss / total
        epoch_acc = correct / total

        training_history.append({
            "epoch": epoch + 1,
            "loss": round(epoch_loss, 6),
            "accuracy": round(epoch_acc, 4),
        })

    # Save model weights
    trained_model_weights = model.state_dict()

    # Update model state
    model_state = {
        "trained": True,
        "num_classes": num_classes,
        "label_to_idx": label_to_idx,
        "idx_to_label": idx_to_label,
        "training_samples": len(training_image_ids),
        "final_accuracy": training_history[-1]["accuracy"] if training_history else None,
        "final_loss": training_history[-1]["loss"] if training_history else None,
    }

    return {
        "message": "Model trained successfully",
        "training_samples": len(training_image_ids),
        "num_classes": num_classes,
        "labels": unique_labels,
        "device": str(device),
        "training_history": training_history,
        "final_accuracy": model_state["final_accuracy"],
    }


@app.post("/model/predict/{image_id}")
def predict_image(image_id: str):
    """Predict the label for an image using the trained model."""
    global trained_model_weights

    if not TORCH_AVAILABLE:
        raise HTTPException(status_code=500, detail="PyTorch is not installed.")

    if not model_state["trained"] or trained_model_weights is None:
        raise HTTPException(status_code=400, detail="Model has not been trained yet.")

    if image_id not in image_store:
        raise HTTPException(status_code=404, detail="Image not found")

    device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
    model = create_model(model_state["num_classes"], freeze_backbone=True)
    model.load_state_dict(trained_model_weights)
    model = model.to(device)
    model.eval()

    transform = transforms.Compose([
        transforms.Resize((224, 224)),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
    ])

    image_data = image_store[image_id]["data"]
    image = Image.open(BytesIO(image_data)).convert("RGB")
    image_tensor = transform(image).unsqueeze(0).to(device)

    with torch.no_grad():
        outputs = model(image_tensor)
        probabilities = torch.softmax(outputs, dim=1)
        confidence, predicted_idx = torch.max(probabilities, 1)

    predicted_label = model_state["idx_to_label"][predicted_idx.item()]

    # Get all class probabilities
    prob_dict = {}
    for idx, prob in enumerate(probabilities[0].cpu().numpy()):
        prob_dict[model_state["idx_to_label"][idx]] = round(float(prob), 4)

    return {
        "image_id": image_id,
        "predicted_label": predicted_label,
        "confidence": round(confidence.item(), 4),
        "class_probabilities": prob_dict,
    }


@app.post("/model/predict_batch")
def predict_batch(image_ids: list[str]):
    """Predict labels for multiple images."""
    if not TORCH_AVAILABLE:
        raise HTTPException(status_code=500, detail="PyTorch is not installed.")

    if not model_state["trained"] or trained_model_weights is None:
        raise HTTPException(status_code=400, detail="Model has not been trained yet.")

    results = []
    for image_id in image_ids:
        try:
            if image_id not in image_store:
                results.append({"image_id": image_id, "status": "error", "detail": "Image not found"})
                continue
            result = predict_image(image_id)
            result["status"] = "success"
            results.append(result)
        except Exception as e:
            results.append({"image_id": image_id, "status": "error", "detail": str(e)})

    return {"predictions": results}


